206	/// Push a human-readable name for the function described by `ar`.
207	///
208	/// C: `static void pushfuncname(lua_State *L, lua_Debug *ar)`
209	fn push_func_name(state: &mut LuaState, ar: &mut LuaDebug) -> Result<(), LuaError> {
210	    if push_global_func_name(state, ar)? {
211	        // C: lua_pushfstring(L, "function '%s'", lua_tostring(L, -1));
212	        let name = state.peek_bytes(-1).unwrap_or_else(|| b"?".to_vec());
213	        state.push_fstring(format_args!("function '{}'", BStr(&name)))?;
214	        // C: lua_remove(L, -2);
215	        state.remove(-2)?;
216	    } else if !ar.namewhat.is_empty() {
217	        // C: lua_pushfstring(L, "%s '%s'", ar->namewhat, ar->name);
218	        let namewhat = ar.namewhat.clone();
219	        let name = ar.name.clone().unwrap_or_else(|| b"?".to_vec());
220	        state.push_fstring(format_args!("{} '{}'", BStr(&namewhat), BStr(&name)))?;
221	    } else if ar.what == b'm' {
222	        // C: lua_pushliteral(L, "main chunk");
223	        state.push_string(b"main chunk")?;
224	    } else if ar.what != b'C' {
225	        // C: lua_pushfstring(L, "function <%s:%d>", ar->short_src, ar->linedefined);
226	        let src = ar.short_src.clone();
227	        let line = ar.linedefined;
228	        state.push_fstring(format_args!("function <{}:{}>", BStr(&src), line))?;
229	    } else {
230	        // C: lua_pushliteral(L, "?");
231	        state.push_string(b"?")?;
232	    }
233	    Ok(())
234	}
