236	/// Binary-search for the last valid stack level in `state`.
237	///
238	/// C: `static int lastlevel(lua_State *L)`
239	fn last_level(state: &mut LuaState) -> i32 {
240	    let mut ar = LuaDebug::default();
241	    let mut li: i32 = 1;
242	    let mut le: i32 = 1;
243	    // C: while (lua_getstack(L, le, &ar)) { li = le; le *= 2; }
244	    while state.get_stack(le, &mut ar) {
245	        li = le;
246	        le *= 2;
247	    }
248	    // binary search
249	    while li < le {
250	        let m = (li + le) / 2;
251	        if state.get_stack(m, &mut ar) {
252	            li = m + 1;
253	        } else {
254	            le = m;
255	        }
256	    }
257	    le - 1
258	}
