260	/// Build a stack traceback string from thread `other` starting at `level`.
261	/// If `msg` is non-None it is prepended on its own line.
262	/// Leaves the result string on top of `state`.
263	///
264	/// C: `LUALIB_API void luaL_traceback(lua_State *L, lua_State *L1, const char *msg, int level)`
265	pub fn traceback(
266	    state: &mut LuaState,
267	    other: &mut LuaState,
268	    msg: Option<&[u8]>,
269	    level: i32,
270	) -> Result<(), LuaError> {
271	    let mut b = LuaBuffer::new();
272	    let mut ar = LuaDebug::default();
273	    let last = last_level(other);
274	    // C: int limit2show = (last - level > LEVELS1 + LEVELS2) ? LEVELS1 : -1;
275	    let mut limit2show: i32 = if last - level > LEVELS1 + LEVELS2 { LEVELS1 } else { -1 };
276	    buf_init(state, &mut b);
277	    if let Some(m) = msg {
278	        add_lstring(&mut b, m);
279	        add_char(&mut b, b'\n');
280	    }
281	    add_lstring(&mut b, b"stack traceback:");
282	    let mut level = level;
283	    while other.get_stack(level, &mut ar) {
284	        level += 1;
285	        if limit2show == 0 {
286	            // C: int n = last - level - LEVELS2 + 1;
287	            let n = last - level - LEVELS2 + 1;
288	            // C: lua_pushfstring(L, "\n\t...\t(skipping %d levels)", n);
289	            state.push_fstring(format_args!("\n\t...\t(skipping {} levels)", n))?;
290	            add_value(state, &mut b)?;
291	            level += n;
292	        } else {
293	            limit2show -= 1;
294	            // C: lua_getinfo(L1, "Slnt", &ar);
295	            other.get_info(b"Slnt", &mut ar)?;
296	            if ar.currentline <= 0 {
297	                // C: lua_pushfstring(L, "\n\t%s: in ", ar.short_src);
298	                let src = ar.short_src.clone();
299	                state.push_fstring(format_args!("\n\t{}: in ", BStr(&src)))?;
300	            } else {
301	                // C: lua_pushfstring(L, "\n\t%s:%d: in ", ar.short_src, ar.currentline);
302	                let src = ar.short_src.clone();
303	                let line = ar.currentline;
304	                state.push_fstring(format_args!("\n\t{}:{}: in ", BStr(&src), line))?;
305	            }
306	            add_value(state, &mut b)?;
307	            push_func_name(state, &mut ar)?;
308	            add_value(state, &mut b)?;
309	            if ar.istailcall {
310	                add_lstring(&mut b, b"\n\t(...tail calls...)");
311	            }
312	        }
313	    }
314	    push_result(state, &mut b)?;
315	    Ok(())
316	}
