788	/// Initialize `buf`, reserve `sz` bytes, and return the writable region.
789	///
790	/// C: `LUALIB_API char *luaL_buffinitsize(lua_State *L, luaL_Buffer *B, size_t sz)`
791	pub fn buf_init_size(
792	    state: &mut LuaState,
793	    buf: &mut LuaBuffer,
794	    sz: usize,
795	) -> Result<(), LuaError> {
796	    buf_init(state, buf);
797	    buf.data.reserve(sz);
798	    Ok(())
799	}
