801	/// Compute a new buffer capacity that accommodates `sz` more bytes,
802	/// growing by ×1.5 or more.
803	///
804	/// C: `static size_t newbuffsize(luaL_Buffer *B, size_t sz)`
805	fn new_buff_size(buf: &LuaBuffer, sz: usize) -> Result<usize, LuaError> {
806	    // C: if (l_unlikely(MAX_SIZET - sz < B->n)) return luaL_error(...)
807	    if usize::MAX - sz < buf.len() {
808	        return Err(LuaError::runtime(format_args!("buffer too large")));
809	    }
810	    let newsize = (buf.data.capacity() / 2) * 3; // ×1.5
811	    if newsize < buf.len() + sz {
812	        Ok(buf.len() + sz)
813	    } else {
814	        Ok(newsize)
815	    }
816	}
