871	/// Push the buffer contents as a Lua string onto `state`'s stack.
872	///
873	/// C: `LUALIB_API void luaL_pushresult(luaL_Buffer *B)`
874	pub fn push_result(state: &mut LuaState, buf: &mut LuaBuffer) -> Result<(), LuaError> {
875	    // C: lua_pushlstring(L, B->b, B->n);
876	    state.push_bytes(&buf.data)?;
877	    // C: if (buffonstack(B)) lua_closeslot(L, -2);
878	    // C: lua_remove(L, -2);  /* remove box or placeholder */
879	    state.remove(-2)?;
880	    Ok(())
