/// C: `CClosure *luaF_newCclosure(lua_State *L, int nupvals)`
pub(crate) fn new_c_closure(
    state: &mut LuaState,
    nupvals: u8,
) -> GcRef<crate::state::LuaClosure> {
    // C: GCObject *o = luaC_newobj(L, LUA_VCCL, sizeCclosure(nupvals));
    //    CClosure *c = gco2ccl(o);
