// C: LUA_RIDX_MAINTHREAD = 1, LUA_RIDX_GLOBALS = 2  (lua.h)
// macros.tsv: LUA_RIDX_MAINTHREAD → const LUA_RIDX_MAINTHREAD: i64 = 1
